import { getSupabaseAdmin } from "@/lib/supabase";

// POST /api/simulation/request
// 답장 시뮬레이터 단건 결제 주문 생성.
// 입력: { parent_order_id, draft_reply, clientToken }
// 출력: { sim_order_id, amount }
//
// parent_order_id(심층분석 주문)가 paid 상태여야 시뮬 주문 생성 가능.
// 사용자 답안은 생성 시 저장해두고, 결제 확정 시 Claude 프롬프트에 주입.
export async function POST(req: Request) {
  try {
    const { parent_order_id, draft_reply, clientToken } = await req.json();

    if (!parent_order_id || typeof parent_order_id !== "string") {
      return Response.json(
        { error: "parent_order_id가 필요해요" },
        { status: 400 }
      );
    }
    if (!draft_reply || typeof draft_reply !== "string" || !draft_reply.trim()) {
      return Response.json(
        { error: "답안 내용을 입력해줘" },
        { status: 400 }
      );
    }
    if (draft_reply.length > 1000) {
      return Response.json(
        { error: "답안은 1000자 이하로 써줘" },
        { status: 400 }
      );
    }
    if (!clientToken || typeof clientToken !== "string") {
      return Response.json(
        { error: "clientToken이 필요해요" },
        { status: 400 }
      );
    }

    const supabase = getSupabaseAdmin();

    // 부모 심층분석 주문 검증 (paid + 분석결과 존재)
    const { data: parent, error: pErr } = await supabase
      .from("orders")
      .select("order_id, status, analysis_result")
      .eq("order_id", parent_order_id)
      .single();

    if (pErr || !parent) {
      return Response.json(
        { error: "원 분석 주문을 찾을 수 없어요" },
        { status: 404 }
      );
    }
    if (parent.status !== "paid" || !parent.analysis_result) {
      return Response.json(
        { error: "먼저 심층 분석을 완료해야 시뮬레이션을 받을 수 있어" },
        { status: 400 }
      );
    }

    // 시뮬 주문 ID 생성: aiunnisim_{timestamp}_{random8}
    const simOrderId =
      "aiunnisim_" +
      Date.now().toString(36) +
      "_" +
      Math.random().toString(36).substring(2, 10);

    const amount = 2900;

    const { error } = await supabase.from("simulations").insert({
      sim_order_id: simOrderId,
      parent_order_id,
      draft_reply: draft_reply.trim(),
      amount,
      status: "pending",
      client_token: clientToken,
    });

    if (error) {
      console.error("Supabase insert error:", error);
      return Response.json(
        { error: "시뮬 주문 생성 실패", debug: error.message },
        { status: 500 }
      );
    }

    return Response.json({ sim_order_id: simOrderId, amount });
  } catch (e: any) {
    console.error("simulation/request error:", e);
    return Response.json(
      { error: "요청 처리 중 오류", debug: e?.message || String(e) },
      { status: 500 }
    );
  }
}
